int main() {
    char str1[] = "Hello";
    char str2[] = "World";
    char result[50];

    printf("Length: %lu\n", strlen(str1));   // 5
    strcpy(result, str1);                     // Copy
    strcat(result, str2);                     // Concat
    printf("Result: %s\n", result);           // HelloWorld

    return 0;
}
