int main() {
    printf("sqrt(16) = %.1f\n",  sqrt(16));   // 4.0
    printf("pow(2,8) = %.0f\n",  pow(2, 8));  // 256
    printf("ceil(4.2)= %.1f\n",  ceil(4.2));  // 5.0
    printf("floor(4.9)= %.1f\n", floor(4.9)); // 4.0
    printf("abs(-10) = %d\n",    abs(-10));    // 10

    return 0;
}
